const e="biologia",i=JSON.parse('[{"id":"bio-001","front":"¿Qué diferencia principal existe entre una biomolécula orgánica y una inorgánica?","back":"Las biomoléculas orgánicas presentan un esqueleto carbonado característico, mientras que las inorgánicas, como el agua o las sales minerales, no lo poseen como rasgo básico.","topic":"Biomoléculas","difficulty":1,"fromOrientaciones":true},{"id":"bio-002","front":"¿Cómo se clasifican las sales minerales según su solubilidad?","back":"Se clasifican en sales solubles, que aparecen disueltas y participan en equilibrio osmótico y pH, y sales insolubles, con función principalmente estructural.","topic":"Biomoléculas","difficulty":1,"fromOrientaciones":true},{"id":"bio-003","front":"¿Qué función biológica general tienen las sales minerales solubles?","back":"Intervienen en el equilibrio osmótico, ayudan a mantener el pH y participan en procesos fisiológicos mediante iones como Na+, K+, Ca2+ y Mg2+.","topic":"Biomoléculas","difficulty":1,"fromOrientaciones":true},{"id":"bio-004","front":"¿Qué función desempeñan las sales minerales insolubles en los seres vivos?","back":"Cumplen sobre todo una función estructural, como ocurre con el fosfato cálcico en huesos y el carbonato cálcico en conchas y caparazones.","topic":"Biomoléculas","difficulty":1,"fromOrientaciones":true},{"id":"bio-005","front":"¿Qué es un enlace iónico?","back":"Es la unión química que se forma por atracción electrostática entre iones con cargas opuestas tras la cesión o captación de electrones.","topic":"Biomoléculas","difficulty":1,"fromOrientaciones":true},{"id":"bio-006","front":"¿Qué es un enlace covalente?","back":"Es un enlace en el que dos átomos comparten uno o más pares de electrones, formando moléculas estables.","topic":"Biomoléculas","difficulty":1,"fromOrientaciones":true},{"id":"bio-007","front":"¿Por qué los puentes de hidrógeno son tan importantes en biología?","back":"Porque estabilizan la estructura del agua y de muchas biomoléculas, como proteínas y ácidos nucleicos, aunque individualmente sean enlaces débiles.","topic":"Biomoléculas","difficulty":2,"fromOrientaciones":true},{"id":"bio-008","front":"¿Qué propiedad del agua explica su gran poder disolvente?","back":"Su polaridad, que permite rodear iones y moléculas polares, facilitando su disolución y transporte en los seres vivos.","topic":"Agua","difficulty":1,"fromOrientaciones":true},{"id":"bio-009","front":"¿Por qué el agua actúa como regulador térmico?","back":"Porque tiene elevado calor específico y calor de vaporización, lo que amortigua los cambios de temperatura en organismos y ecosistemas.","topic":"Agua","difficulty":2,"fromOrientaciones":true},{"id":"bio-010","front":"¿Qué es un monosacárido?","back":"Es el glúcido más simple, no hidrolizable, formado por una sola unidad y con función energética o estructural según el caso.","topic":"Glúcidos","difficulty":1,"fromOrientaciones":true},{"id":"bio-011","front":"¿Cómo se clasifican los monosacáridos según su grupo funcional?","back":"Se clasifican en aldosas, si tienen grupo aldehído, y cetosas, si presentan grupo cetona.","topic":"Glúcidos","difficulty":1,"fromOrientaciones":true},{"id":"bio-012","front":"¿Qué diferencia hay entre una pentosa y una hexosa?","back":"La pentosa tiene cinco átomos de carbono y la hexosa seis. Ejemplos son la ribosa y la glucosa, respectivamente.","topic":"Glúcidos","difficulty":1,"fromOrientaciones":true},{"id":"bio-013","front":"¿Qué es un carbono asimétrico en un monosacárido?","back":"Es un átomo de carbono unido a cuatro sustituyentes distintos, lo que permite la existencia de isomería óptica.","topic":"Glúcidos","difficulty":2,"fromOrientaciones":true},{"id":"bio-014","front":"¿Qué son los enantiómeros?","back":"Son moléculas que son imágenes especulares no superponibles entre sí, como las formas D y L de algunos monosacáridos.","topic":"Glúcidos","difficulty":2,"fromOrientaciones":true},{"id":"bio-015","front":"¿Qué es el carbono anomérico de un monosacárido?","back":"Es el carbono que procede del grupo carbonilo y que, al cerrarse la molécula en forma cíclica, determina las formas alfa o beta.","topic":"Glúcidos","difficulty":3,"fromOrientaciones":true},{"id":"bio-016","front":"¿Qué caracteriza al enlace O-glucosídico?","back":"Es el enlace covalente típico de disacáridos y polisacáridos, formado entre grupos hidroxilo de dos monosacáridos con liberación de agua.","topic":"Glúcidos","difficulty":2,"fromOrientaciones":true},{"id":"bio-017","front":"¿Qué función desempeñan los polisacáridos de reserva?","back":"Almacenan energía para su uso posterior. Los principales son el almidón en vegetales y el glucógeno en animales y hongos.","topic":"Glúcidos","difficulty":1,"fromOrientaciones":true},{"id":"bio-018","front":"¿Qué polisacáridos cumplen función estructural?","back":"La celulosa, componente de la pared celular vegetal, y la quitina, presente en artrópodos y pared de muchos hongos.","topic":"Glúcidos","difficulty":1,"fromOrientaciones":true},{"id":"bio-019","front":"¿Por qué la diferencia entre enlaces alfa y beta es importante en los polisacáridos?","back":"Porque condiciona su estructura y función: los enlaces alfa suelen asociarse a reserva energética y los beta a función estructural.","topic":"Glúcidos","difficulty":2,"fromOrientaciones":true},{"id":"bio-020","front":"¿Qué es un ácido graso?","back":"Es una molécula formada por una larga cadena hidrocarbonada y un grupo carboxilo terminal, componente básico de muchos lípidos.","topic":"Lípidos","difficulty":1,"fromOrientaciones":true},{"id":"bio-021","front":"¿Cómo se clasifican los ácidos grasos según la presencia de dobles enlaces?","back":"Se clasifican en saturados, si no tienen dobles enlaces, e insaturados, si presentan uno o varios dobles enlaces.","topic":"Lípidos","difficulty":1,"fromOrientaciones":true},{"id":"bio-022","front":"¿Qué relación existe entre insaturación y punto de fusión en los ácidos grasos?","back":"Cuantos más dobles enlaces tenga un ácido graso, menor suele ser su punto de fusión y mayor su fluidez a temperatura ambiente.","topic":"Lípidos","difficulty":2,"fromOrientaciones":true},{"id":"bio-023","front":"¿Qué significa que un lípido sea saponificable?","back":"Significa que contiene ácidos grasos unidos mediante enlaces éster y puede hidrolizarse, por ejemplo en presencia de bases.","topic":"Lípidos","difficulty":2,"fromOrientaciones":true},{"id":"bio-024","front":"¿Qué función principal tienen los triacilglicéridos?","back":"Cumplen una función de reserva energética, además de aislamiento térmico y protección mecánica en muchos organismos.","topic":"Lípidos","difficulty":1,"fromOrientaciones":true},{"id":"bio-025","front":"¿Por qué los fosfolípidos son esenciales en las membranas biológicas?","back":"Porque son anfipáticos y se organizan en bicapa, formando la base estructural de las membranas celulares.","topic":"Lípidos","difficulty":2,"fromOrientaciones":true},{"id":"bio-026","front":"¿Qué funciones biológicas destacan en los esteroides?","back":"Actúan como componentes de membrana, como precursores de hormonas y, en algunos casos, de vitaminas.","topic":"Lípidos","difficulty":2,"fromOrientaciones":true},{"id":"bio-027","front":"¿Qué son las proteínas?","back":"Son macromoléculas formadas por aminoácidos unidos mediante enlaces peptídicos y desempeñan funciones muy diversas en los seres vivos.","topic":"Proteínas","difficulty":1,"fromOrientaciones":true},{"id":"bio-028","front":"¿Qué es un aminoácido?","back":"Es la unidad básica de las proteínas y posee un carbono alfa unido a un grupo amino, un carboxilo, un hidrógeno y un radical variable.","topic":"Proteínas","difficulty":1,"fromOrientaciones":true},{"id":"bio-029","front":"¿Qué determina la diversidad de los aminoácidos?","back":"La naturaleza química de su radical o cadena lateral, que cambia de unos aminoácidos a otros.","topic":"Proteínas","difficulty":1,"fromOrientaciones":true},{"id":"bio-030","front":"¿Qué es el enlace peptídico?","back":"Es el enlace covalente que une el grupo carboxilo de un aminoácido con el grupo amino de otro, liberando una molécula de agua.","topic":"Proteínas","difficulty":1,"fromOrientaciones":true},{"id":"bio-031","front":"¿Qué representa la estructura primaria de una proteína?","back":"La secuencia lineal de aminoácidos de la cadena polipeptídica, que condiciona los niveles estructurales superiores.","topic":"Proteínas","difficulty":1,"fromOrientaciones":true},{"id":"bio-032","front":"¿Qué tipos de estructura secundaria pueden presentar las proteínas?","back":"Principalmente alfa-hélice y lámina o beta-plegada, estabilizadas sobre todo por puentes de hidrógeno.","topic":"Proteínas","difficulty":2,"fromOrientaciones":true},{"id":"bio-033","front":"¿Qué es la estructura terciaria de una proteína?","back":"Es el plegamiento tridimensional global de una cadena polipeptídica, estabilizado por distintas interacciones entre radicales.","topic":"Proteínas","difficulty":2,"fromOrientaciones":true},{"id":"bio-034","front":"¿Qué es la estructura cuaternaria de una proteína?","back":"Es la asociación de varias cadenas polipeptídicas o subunidades para formar una proteína funcional.","topic":"Proteínas","difficulty":2,"fromOrientaciones":true},{"id":"bio-035","front":"¿Qué diferencia general existe entre una proteína globular y una fibrosa?","back":"Las globulares suelen ser compactas y funcionalmente activas en medio acuoso, mientras que las fibrosas suelen tener función estructural.","topic":"Proteínas","difficulty":2,"fromOrientaciones":true},{"id":"bio-036","front":"¿Qué es la desnaturalización de una proteína?","back":"Es la pérdida de su conformación espacial sin romper normalmente la estructura primaria, lo que suele implicar pérdida de función.","topic":"Proteínas","difficulty":2,"fromOrientaciones":true},{"id":"bio-037","front":"¿Qué factores pueden provocar la desnaturalización de una proteína?","back":"Principalmente cambios bruscos de temperatura y de pH, aunque también pueden influir otras condiciones físico-químicas.","topic":"Proteínas","difficulty":1,"fromOrientaciones":true},{"id":"bio-038","front":"¿Qué es una enzima?","back":"Es un biocatalizador, generalmente proteico, que acelera una reacción química disminuyendo la energía de activación sin consumirse.","topic":"Enzimología","difficulty":1,"fromOrientaciones":true},{"id":"bio-039","front":"¿Qué es el centro activo de una enzima?","back":"Es la región específica donde se une el sustrato y tiene lugar la catálisis, lo que explica la especificidad enzimática.","topic":"Enzimología","difficulty":2,"fromOrientaciones":true},{"id":"bio-040","front":"¿Qué función tienen los cofactores y las coenzimas en la actividad enzimática?","back":"Ayudan a la enzima en su función catalítica. Los cofactores suelen ser iones o moléculas simples y las coenzimas, compuestos orgánicos.","topic":"Enzimología","difficulty":2,"fromOrientaciones":true},{"id":"bio-041","front":"¿Cómo influye la concentración de sustrato en la velocidad de una reacción enzimática?","back":"La velocidad aumenta al incrementarse el sustrato hasta que la enzima se satura y se alcanza una velocidad máxima.","topic":"Enzimología","difficulty":2,"fromOrientaciones":true},{"id":"bio-042","front":"¿Por qué las enzimas disminuyen la energía de activación?","back":"Porque facilitan la formación del complejo enzima-sustrato y proporcionan una vía de reacción más favorable energéticamente.","topic":"Enzimología","difficulty":3,"fromOrientaciones":true},{"id":"bio-043","front":"¿Qué diferencia existe entre inhibición competitiva y no competitiva?","back":"En la competitiva, el inhibidor compite con el sustrato por el centro activo; en la no competitiva, se une a otro lugar y altera la actividad.","topic":"Enzimología","difficulty":3,"fromOrientaciones":true},{"id":"bio-044","front":"¿Qué es un nucleótido?","back":"Es la unidad básica de los ácidos nucleicos y está formado por una base nitrogenada, una pentosa y uno o más grupos fosfato.","topic":"Ácidos nucleicos","difficulty":1,"fromOrientaciones":true},{"id":"bio-045","front":"¿Cómo se distinguen las bases nitrogenadas púricas de las pirimidínicas?","back":"Las púricas tienen dos anillos y las pirimidínicas uno. Adenina y guanina son púricas; citosina, timina y uracilo son pirimidínicas.","topic":"Ácidos nucleicos","difficulty":2,"fromOrientaciones":true},{"id":"bio-046","front":"¿Qué funciones pueden desempeñar los nucleótidos además de formar ácidos nucleicos?","back":"Tienen función energética, como el ATP, y también coenzimática y estructural en distintas moléculas celulares.","topic":"Ácidos nucleicos","difficulty":2,"fromOrientaciones":true},{"id":"bio-047","front":"¿Qué caracteriza al enlace fosfodiéster?","back":"Es el enlace covalente que une nucleótidos consecutivos en una cadena de ácido nucleico mediante el fosfato y las pentosas.","topic":"Ácidos nucleicos","difficulty":2,"fromOrientaciones":true},{"id":"bio-048","front":"¿Qué diferencia química básica existe entre el ADN y el ARN?","back":"El ADN contiene desoxirribosa y timina, mientras que el ARN contiene ribosa y uracilo.","topic":"Ácidos nucleicos","difficulty":1,"fromOrientaciones":true},{"id":"bio-049","front":"¿Qué función cumple el ADN en la célula?","back":"Almacena y transmite la información genética, y esa función está ligada a su capacidad de replicarse y servir de molde para la síntesis de ARN.","topic":"Ácidos nucleicos","difficulty":1,"fromOrientaciones":true},{"id":"bio-050","front":"¿Qué tipos principales de ARN intervienen en la síntesis de proteínas?","back":"El ARNm lleva la información genética, el ARNr forma parte de los ribosomas y el ARNt transporta aminoácidos al ribosoma.","topic":"Ácidos nucleicos","difficulty":1,"fromOrientaciones":true},{"id":"bio-051","front":"¿Qué es la replicación del ADN?","back":"Es el proceso mediante el cual una molécula de ADN se duplica para originar dos copias antes de la división celular.","topic":"Genética molecular","difficulty":1,"fromOrientaciones":true},{"id":"bio-052","front":"¿Qué significa que la replicación del ADN sea semiconservativa?","back":"Significa que cada molécula hija conserva una hebra original y sintetiza una nueva hebra complementaria.","topic":"Genética molecular","difficulty":2,"fromOrientaciones":true},{"id":"bio-053","front":"¿Qué significa que la replicación del ADN sea bidireccional?","back":"Significa que, desde el origen de replicación, el proceso avanza en dos sentidos opuestos formando dos horquillas de replicación.","topic":"Genética molecular","difficulty":2,"fromOrientaciones":true},{"id":"bio-054","front":"¿Qué función desempeña la helicasa en la replicación del ADN?","back":"Separa las dos hebras de ADN rompiendo los puentes de hidrógeno para permitir la copia de cada cadena.","topic":"Genética molecular","difficulty":2,"fromOrientaciones":true},{"id":"bio-055","front":"¿Qué función tiene la ADN polimerasa?","back":"Sintetiza una nueva hebra de ADN añadiendo nucleótidos complementarios sobre una cadena molde.","topic":"Genética molecular","difficulty":1,"fromOrientaciones":true},{"id":"bio-056","front":"¿Para qué sirve la ligasa en la replicación del ADN?","back":"Une fragmentos de ADN mediante enlaces fosfodiéster, especialmente en la hebra retardada.","topic":"Genética molecular","difficulty":2,"fromOrientaciones":true},{"id":"bio-057","front":"¿Qué papel cumplen las proteínas SSB durante la replicación?","back":"Mantienen separadas y estabilizadas las hebras de ADN abiertas para que no vuelvan a unirse mientras se copian.","topic":"Genética molecular","difficulty":3,"fromOrientaciones":true},{"id":"bio-058","front":"¿Dónde ocurre la replicación del ADN en las células procariotas?","back":"Tiene lugar en el citoplasma, ya que las procariotas no poseen núcleo delimitado por membrana.","topic":"Genética molecular","difficulty":1,"fromOrientaciones":true},{"id":"bio-059","front":"¿Dónde ocurre la replicación del ADN en las células eucariotas?","back":"Se realiza principalmente en el núcleo, antes de la división celular.","topic":"Genética molecular","difficulty":1,"fromOrientaciones":true},{"id":"bio-060","front":"¿Qué diferencia general existe entre el ADN de procariotas y eucariotas respecto a su forma?","back":"En procariotas suele ser circular, mientras que en eucariotas es lineal y se organiza en cromosomas.","topic":"Genética molecular","difficulty":1,"fromOrientaciones":true},{"id":"bio-061","front":"¿Qué es la transcripción?","back":"Es el proceso por el que se sintetiza una molécula de ARN usando una hebra de ADN como molde.","topic":"Genética molecular","difficulty":1,"fromOrientaciones":true},{"id":"bio-062","front":"¿Qué es la cadena molde del ADN?","back":"Es la hebra de ADN que sirve de patrón para sintetizar una molécula de ARN complementaria durante la transcripción.","topic":"Genética molecular","difficulty":2,"fromOrientaciones":true},{"id":"bio-063","front":"¿Qué es la cadena codificante del ADN?","back":"Es la hebra de ADN complementaria a la molde y presenta la misma secuencia que el ARNm, salvo que tiene timina en lugar de uracilo.","topic":"Genética molecular","difficulty":2,"fromOrientaciones":true},{"id":"bio-064","front":"¿Qué enzima realiza la transcripción?","back":"La ARN polimerasa, que incorpora ribonucleótidos complementarios y sintetiza la cadena de ARN.","topic":"Genética molecular","difficulty":1,"fromOrientaciones":true},{"id":"bio-065","front":"¿Qué función tiene la región promotora de un gen?","back":"Es la zona del ADN donde se une la ARN polimerasa para iniciar la transcripción.","topic":"Genética molecular","difficulty":2,"fromOrientaciones":true},{"id":"bio-066","front":"¿Qué es la traducción?","back":"Es el proceso por el que la información del ARNm dirige la unión ordenada de aminoácidos para formar una proteína.","topic":"Genética molecular","difficulty":1,"fromOrientaciones":true},{"id":"bio-067","front":"¿Qué diferencia importante existe entre la transcripción eucariota y procariota?","back":"En eucariotas ocurre en el núcleo y el ARN suele necesitar maduración; en procariotas ocurre en el citoplasma y no requiere esa maduración.","topic":"Genética molecular","difficulty":2,"fromOrientaciones":true},{"id":"bio-068","front":"¿Cuántos tipos principales de ARN polimerasa intervienen en eucariotas?","back":"En eucariotas intervienen tres tipos principales de ARN polimerasa: I, II y III.","topic":"Genética molecular","difficulty":2,"fromOrientaciones":true},{"id":"bio-069","front":"¿Por qué el código genético se considera degenerado?","back":"Porque varios codones distintos pueden codificar el mismo aminoácido.","topic":"Genética molecular","difficulty":2,"fromOrientaciones":true},{"id":"bio-070","front":"¿Qué significa que el código genético sea prácticamente universal?","back":"Significa que, salvo excepciones, los mismos codones codifican los mismos aminoácidos en la mayoría de los seres vivos.","topic":"Genética molecular","difficulty":2,"fromOrientaciones":true},{"id":"bio-071","front":"¿Qué es una mutación?","back":"Es una alteración estable en la secuencia del material genético que puede afectar a genes, cromosomas o al genoma completo.","topic":"Genética molecular","difficulty":1,"fromOrientaciones":true},{"id":"bio-072","front":"¿Qué es una mutación génica?","back":"Es un cambio en la secuencia de nucleótidos de un gen concreto, como una sustitución, inserción o deleción.","topic":"Genética molecular","difficulty":2,"fromOrientaciones":true},{"id":"bio-073","front":"¿Qué es una mutación cromosómica?","back":"Es una alteración en la estructura de uno o varios cromosomas, como deleciones, duplicaciones, inversiones o translocaciones.","topic":"Genética molecular","difficulty":2,"fromOrientaciones":true},{"id":"bio-074","front":"¿Qué es una mutación genómica?","back":"Es una alteración en el número de cromosomas de una célula, como ocurre en aneuploidías o poliploidías.","topic":"Genética molecular","difficulty":2,"fromOrientaciones":true},{"id":"bio-075","front":"¿Qué son los agentes mutagénicos?","back":"Son factores físicos, químicos o biológicos capaces de aumentar la frecuencia de mutaciones en el material genético.","topic":"Genética molecular","difficulty":1,"fromOrientaciones":true},{"id":"bio-076","front":"¿Qué es una célula procariota?","back":"Es una célula sin núcleo verdadero ni orgánulos membranosos, con el ADN situado en el citoplasma.","topic":"Biología celular","difficulty":1,"fromOrientaciones":true},{"id":"bio-077","front":"¿Qué es una célula eucariota?","back":"Es una célula con núcleo delimitado por membrana y con orgánulos membranosos especializados.","topic":"Biología celular","difficulty":1,"fromOrientaciones":true},{"id":"bio-078","front":"¿Qué es la membrana plasmática?","back":"Es la envoltura celular formada por una bicapa lipídica con proteínas, que delimita la célula y regula el intercambio de sustancias.","topic":"Biología celular","difficulty":1,"fromOrientaciones":true},{"id":"bio-079","front":"¿Qué significa que la membrana plasmática tenga estructura de mosaico fluido?","back":"Significa que la bicapa lipídica es dinámica y que sus proteínas pueden estar incrustadas y moverse lateralmente en ella.","topic":"Biología celular","difficulty":2,"fromOrientaciones":true},{"id":"bio-080","front":"¿Qué función cumple el colesterol en la membrana plasmática?","back":"Contribuye a regular la fluidez y estabilidad de la membrana celular.","topic":"Biología celular","difficulty":2,"fromOrientaciones":true},{"id":"bio-081","front":"¿Qué función cumplen los oligosacáridos de membrana en el reconocimiento celular?","back":"Actúan como señales de identificación y participan en el reconocimiento y comunicación entre células.","topic":"Biología celular","difficulty":2,"fromOrientaciones":true},{"id":"bio-082","front":"¿Qué función tienen las proteínas transmembrana?","back":"Participan en el transporte de sustancias, la recepción de señales y otras funciones asociadas a la membrana.","topic":"Biología celular","difficulty":2,"fromOrientaciones":true},{"id":"bio-083","front":"¿Qué es una mitocondria?","back":"Es un orgánulo de células eucariotas donde tiene lugar gran parte de la respiración celular y de la producción de ATP.","topic":"Biología celular","difficulty":1,"fromOrientaciones":true},{"id":"bio-084","front":"¿Qué función general tiene el centrosoma?","back":"Actúa como organizador de microtúbulos y participa en la formación del huso durante la división celular.","topic":"Biología celular","difficulty":2,"fromOrientaciones":true},{"id":"bio-085","front":"¿Qué es el ciclo celular?","back":"Es la secuencia ordenada de etapas por las que pasa una célula desde que se forma hasta que se divide.","topic":"Biología celular","difficulty":1,"fromOrientaciones":true},{"id":"bio-086","front":"¿Qué ocurre en la interfase del ciclo celular?","back":"La célula crece, realiza su actividad metabólica y, antes de dividirse, replica su ADN.","topic":"Biología celular","difficulty":1,"fromOrientaciones":true},{"id":"bio-087","front":"¿Qué es la mitosis?","back":"Es una división nuclear en la que se reparte equitativamente el material genético para originar dos células hijas con la misma dotación cromosómica.","topic":"Biología celular","difficulty":1,"fromOrientaciones":true},{"id":"bio-088","front":"¿Qué significado biológico tiene la mitosis en organismos pluricelulares?","back":"Permite el crecimiento, la renovación tisular y la reparación de tejidos conservando la información genética.","topic":"Biología celular","difficulty":2,"fromOrientaciones":true},{"id":"bio-089","front":"¿Qué significado biológico tiene la mitosis en organismos unicelulares?","back":"Constituye un mecanismo básico de reproducción asexual.","topic":"Biología celular","difficulty":1,"fromOrientaciones":true},{"id":"bio-090","front":"¿Qué es la citocinesis?","back":"Es la división del citoplasma que ocurre al final de la división celular y separa físicamente las dos células hijas.","topic":"Biología celular","difficulty":1,"fromOrientaciones":true},{"id":"bio-091","front":"¿Qué diferencia básica existe entre la citocinesis animal y la vegetal?","back":"En células animales suele producirse por estrangulamiento de la membrana, y en vegetales por formación de una placa celular.","topic":"Biología celular","difficulty":2,"fromOrientaciones":true},{"id":"bio-092","front":"¿Qué es la meiosis?","back":"Es una división celular reductora que origina células haploides a partir de una célula diploide y es esencial en la reproducción sexual.","topic":"Biología celular","difficulty":1,"fromOrientaciones":true},{"id":"bio-093","front":"¿Por qué la meiosis es imprescindible en la formación de gametos?","back":"Porque reduce a la mitad el número de cromosomas y permite que, tras la fecundación, se mantenga constante el número cromosómico de la especie.","topic":"Biología celular","difficulty":2,"fromOrientaciones":true},{"id":"bio-094","front":"¿Qué es el sobrecruzamiento en la meiosis?","back":"Es el intercambio de fragmentos entre cromosomas homólogos durante la meiosis, generando recombinación genética.","topic":"Biología celular","difficulty":3,"fromOrientaciones":true},{"id":"bio-095","front":"¿Por qué la meiosis favorece la variabilidad genética?","back":"Porque en ella ocurren recombinación génica y segregación cromosómica, a lo que se suma la unión al azar de los gametos en la fecundación.","topic":"Biología celular","difficulty":2,"fromOrientaciones":true},{"id":"bio-096","front":"¿Qué diferencia fundamental existe entre mitosis y meiosis respecto al resultado final?","back":"La mitosis origina células con la misma dotación cromosómica que la célula madre, mientras que la meiosis produce células haploides.","topic":"Biología celular","difficulty":2,"fromOrientaciones":true},{"id":"bio-097","front":"¿Qué es el cáncer desde el punto de vista celular?","back":"Es una alteración del ciclo celular que provoca proliferación descontrolada de células.","topic":"Biología celular","difficulty":1,"fromOrientaciones":true},{"id":"bio-098","front":"¿Cómo se relaciona el cáncer con las mutaciones?","back":"Muchas mutaciones afectan a genes que regulan el ciclo celular, lo que puede favorecer la división celular anormal.","topic":"Biología celular","difficulty":2,"fromOrientaciones":true},{"id":"bio-099","front":"¿Qué tipos de agentes pueden aumentar el riesgo de cáncer al actuar como mutagénicos?","back":"Agentes físicos, químicos y biológicos que dañan el ADN o alteran los mecanismos de control celular.","topic":"Biología celular","difficulty":2,"fromOrientaciones":true},{"id":"bio-100","front":"¿Por qué los estilos de vida saludables ayudan a prevenir algunos cánceres?","back":"Porque reducen la exposición a factores mutagénicos y disminuyen la probabilidad de alteraciones en el ciclo celular.","topic":"Biología celular","difficulty":1,"fromOrientaciones":true},{"id":"bio-101","front":"¿Qué es el metabolismo?","back":"Es el conjunto de reacciones químicas que tienen lugar en la célula para transformar materia y energía y mantener la vida.","topic":"Metabolismo","difficulty":1,"fromOrientaciones":true},{"id":"bio-102","front":"¿Qué diferencia existe entre nutrición autótrofa y heterótrofa?","back":"La nutrición autótrofa utiliza materia inorgánica para sintetizar compuestos orgánicos, mientras que la heterótrofa obtiene materia orgánica ya elaborada.","topic":"Metabolismo","difficulty":1,"fromOrientaciones":true},{"id":"bio-103","front":"¿Qué diferencia básica existe entre anabolismo y catabolismo?","back":"El anabolismo sintetiza moléculas complejas y consume energía; el catabolismo degrada moléculas y libera energía.","topic":"Metabolismo","difficulty":1,"fromOrientaciones":true},{"id":"bio-104","front":"¿Qué caracteriza a las reacciones catabólicas?","back":"Son reacciones de degradación y oxidación que transforman moléculas complejas en otras más sencillas liberando energía.","topic":"Metabolismo","difficulty":2,"fromOrientaciones":true},{"id":"bio-105","front":"¿Qué caracteriza a las reacciones anabólicas?","back":"Son reacciones de síntesis y reducción que forman moléculas complejas a partir de otras sencillas con consumo de energía.","topic":"Metabolismo","difficulty":2,"fromOrientaciones":true},{"id":"bio-106","front":"¿Qué es la respiración celular?","back":"Es un proceso catabólico por el que la célula obtiene energía mediante la oxidación de moléculas orgánicas.","topic":"Metabolismo","difficulty":1,"fromOrientaciones":true},{"id":"bio-107","front":"¿Qué es la glucólisis?","back":"Es la vía catabólica que degrada una molécula de glucosa hasta piruvato en el citosol, obteniendo ATP y poder reductor.","topic":"Metabolismo","difficulty":2,"fromOrientaciones":true},{"id":"bio-108","front":"¿Dónde tiene lugar la glucólisis?","back":"Ocurre en el citosol, tanto en células procariotas como eucariotas.","topic":"Metabolismo","difficulty":1,"fromOrientaciones":true},{"id":"bio-109","front":"¿Qué producto final inmediato se obtiene en la glucólisis a partir de la glucosa?","back":"Se obtienen moléculas de piruvato, además de una pequeña cantidad de ATP y NADH.","topic":"Metabolismo","difficulty":2,"fromOrientaciones":true},{"id":"bio-110","front":"¿Qué es el ciclo de Krebs?","back":"Es una ruta metabólica aerobia que oxida el acetil-CoA y genera CO2, NADH, FADH2 y algo de ATP o GTP.","topic":"Metabolismo","difficulty":2,"fromOrientaciones":true},{"id":"bio-111","front":"¿Dónde se localiza el ciclo de Krebs en células eucariotas?","back":"Tiene lugar en la matriz mitocondrial.","topic":"Metabolismo","difficulty":1,"fromOrientaciones":true},{"id":"bio-112","front":"¿Qué función tiene la cadena de transporte de electrones en la respiración celular?","back":"Transfiere electrones a través de complejos de membrana y utiliza la energía liberada para generar un gradiente que permite sintetizar ATP.","topic":"Metabolismo","difficulty":2,"fromOrientaciones":true},{"id":"bio-113","front":"¿Qué es la fosforilación oxidativa?","back":"Es la síntesis de ATP acoplada al transporte de electrones y al gradiente de protones generado en la membrana interna mitocondrial.","topic":"Metabolismo","difficulty":3,"fromOrientaciones":true},{"id":"bio-114","front":"¿Qué es la beta-oxidación de los ácidos grasos?","back":"Es una vía catabólica que degrada ácidos grasos en fragmentos de acetil-CoA, generando además NADH y FADH2.","topic":"Metabolismo","difficulty":2,"fromOrientaciones":true},{"id":"bio-115","front":"¿Por qué los ácidos grasos proporcionan más energía que la glucosa?","back":"Porque contienen más enlaces reducidos y, al degradarse, generan más acetil-CoA y más coenzimas reducidas para producir ATP.","topic":"Metabolismo","difficulty":3,"fromOrientaciones":true},{"id":"bio-116","front":"¿Qué es la fermentación?","back":"Es una vía catabólica de oxidación incompleta de la glucosa que se realiza sin usar oxígeno y produce menos energía que la respiración.","topic":"Metabolismo","difficulty":1,"fromOrientaciones":true},{"id":"bio-117","front":"¿Qué dos tipos principales de fermentación se estudian en Biología de 2º de Bachillerato?","back":"La fermentación láctica y la fermentación alcohólica.","topic":"Metabolismo","difficulty":1,"fromOrientaciones":true},{"id":"bio-118","front":"¿Qué productos finales se obtienen en la fermentación láctica?","back":"Se obtiene ácido láctico a partir del piruvato, regenerándose además el NAD+ necesario para mantener la glucólisis.","topic":"Metabolismo","difficulty":2,"fromOrientaciones":true},{"id":"bio-119","front":"¿Qué productos finales se obtienen en la fermentación alcohólica?","back":"Se producen etanol y dióxido de carbono, regenerándose también NAD+.","topic":"Metabolismo","difficulty":2,"fromOrientaciones":true},{"id":"bio-120","front":"¿Por qué la fermentación tiene menor rendimiento energético que la respiración celular?","back":"Porque la oxidación de la glucosa es incompleta y solo se obtiene el ATP producido en la glucólisis.","topic":"Metabolismo","difficulty":2,"fromOrientaciones":true},{"id":"bio-121","front":"¿Qué interés industrial tiene la fermentación alcohólica?","back":"Se emplea en la elaboración de bebidas alcohólicas y en la panificación por la producción de etanol y CO2.","topic":"Metabolismo","difficulty":1,"fromOrientaciones":true},{"id":"bio-122","front":"¿Qué interés industrial tiene la fermentación láctica?","back":"Se utiliza en la producción de yogur, quesos y otros alimentos fermentados.","topic":"Metabolismo","difficulty":1,"fromOrientaciones":true},{"id":"bio-123","front":"¿Qué relación existe entre catabolismo y anabolismo?","back":"La energía y los metabolitos obtenidos en el catabolismo son utilizados por la célula en los procesos anabólicos de síntesis.","topic":"Metabolismo","difficulty":2,"fromOrientaciones":true},{"id":"bio-124","front":"¿Qué es la fotosíntesis oxigénica?","back":"Es el proceso fotosintético en el que se utiliza agua como dador de electrones y se libera oxígeno como producto.","topic":"Metabolismo vegetal","difficulty":2,"fromOrientaciones":true},{"id":"bio-125","front":"¿Qué es la fotosíntesis anoxigénica?","back":"Es un tipo de fotosíntesis en la que no se libera oxígeno porque no se utiliza agua como donador de electrones.","topic":"Metabolismo vegetal","difficulty":3,"fromOrientaciones":true},{"id":"bio-126","front":"¿Qué dos grandes fases se distinguen en la fotosíntesis?","back":"La fase fotoquímica y la fase de fijación de carbono o biosintética.","topic":"Metabolismo vegetal","difficulty":1,"fromOrientaciones":true},{"id":"bio-127","front":"¿Dónde se localiza la fase fotoquímica de la fotosíntesis en el cloroplasto?","back":"Tiene lugar en las membranas de los tilacoides, donde se encuentran los fotosistemas y la cadena de transporte electrónico.","topic":"Metabolismo vegetal","difficulty":2,"fromOrientaciones":true},{"id":"bio-128","front":"¿Dónde se localiza la fase de fijación de carbono de la fotosíntesis en el cloroplasto?","back":"Se desarrolla en el estroma del cloroplasto.","topic":"Metabolismo vegetal","difficulty":1,"fromOrientaciones":true},{"id":"bio-129","front":"¿Qué ocurre en la fotólisis del agua durante la fotosíntesis?","back":"El agua se rompe por acción de la luz, liberando electrones, protones y oxígeno.","topic":"Metabolismo vegetal","difficulty":2,"fromOrientaciones":true},{"id":"bio-130","front":"¿Qué moléculas energéticas se producen en la fase fotoquímica de la fotosíntesis?","back":"Se forman ATP y NADPH, que luego se emplean en la fijación de carbono.","topic":"Metabolismo vegetal","difficulty":2,"fromOrientaciones":true},{"id":"bio-131","front":"¿Qué es el ciclo de Calvin?","back":"Es el conjunto de reacciones de la fase biosintética de la fotosíntesis en las que se fija CO2 y se forman compuestos orgánicos.","topic":"Metabolismo vegetal","difficulty":2,"fromOrientaciones":true},{"id":"bio-132","front":"¿Por qué la fotosíntesis es esencial para la biosfera?","back":"Porque produce materia orgánica a partir de compuestos inorgánicos y libera oxígeno, sosteniendo la mayor parte de las cadenas tróficas.","topic":"Metabolismo vegetal","difficulty":1,"fromOrientaciones":true},{"id":"bio-133","front":"¿Qué es la quimiosíntesis?","back":"Es un proceso autótrofo en el que algunos organismos obtienen energía de reacciones químicas de oxidación de compuestos inorgánicos.","topic":"Metabolismo","difficulty":2,"fromOrientaciones":true},{"id":"bio-134","front":"¿Qué es la biotecnología?","back":"Es la aplicación de organismos, células o moléculas biológicas para obtener productos o procesos útiles para el ser humano.","topic":"Biotecnología","difficulty":1,"fromOrientaciones":true},{"id":"bio-135","front":"¿Qué es la ingeniería genética?","back":"Es el conjunto de técnicas que permiten modificar, aislar, recombinar o transferir material genético de forma dirigida.","topic":"Biotecnología","difficulty":1,"fromOrientaciones":true},{"id":"bio-136","front":"¿Qué es la PCR?","back":"Es una técnica que permite amplificar fragmentos concretos de ADN in vitro, obteniendo muchas copias a partir de una pequeña muestra.","topic":"Biotecnología","difficulty":2,"fromOrientaciones":true},{"id":"bio-137","front":"¿Para qué sirven las enzimas de restricción en biotecnología?","back":"Cortan el ADN en secuencias específicas, lo que permite aislar fragmentos y manipularlos en técnicas de ingeniería genética.","topic":"Biotecnología","difficulty":2,"fromOrientaciones":true},{"id":"bio-138","front":"¿Qué es el ADN recombinante?","back":"Es una molécula de ADN formada por la unión de fragmentos procedentes de distintos orígenes.","topic":"Biotecnología","difficulty":2,"fromOrientaciones":true},{"id":"bio-139","front":"¿Qué es la clonación molecular?","back":"Es una técnica que permite obtener múltiples copias de un fragmento de ADN tras insertarlo en un vector y replicarlo en una célula hospedadora.","topic":"Biotecnología","difficulty":3,"fromOrientaciones":true},{"id":"bio-140","front":"¿Qué es un organismo modificado genéticamente?","back":"Es un ser vivo cuyo material genético ha sido alterado artificialmente mediante técnicas de ingeniería genética.","topic":"Biotecnología","difficulty":1,"fromOrientaciones":true},{"id":"bio-141","front":"¿Qué es CRISPR-Cas?","back":"Es una herramienta de edición genética que permite cortar y modificar secuencias concretas de ADN con gran precisión.","topic":"Biotecnología","difficulty":2,"fromOrientaciones":true},{"id":"bio-142","front":"¿Qué aplicación médica tienen los microorganismos recombinantes?","back":"Pueden emplearse para producir sustancias de interés terapéutico como insulina, hormona del crecimiento, antibióticos o vacunas recombinantes.","topic":"Biotecnología","difficulty":2,"fromOrientaciones":true},{"id":"bio-143","front":"¿Qué es la inmunidad?","back":"Es la capacidad del organismo para reconocer y defenderse frente a agentes extraños o potencialmente patógenos.","topic":"Inmunología","difficulty":1,"fromOrientaciones":true},{"id":"bio-144","front":"¿Qué es un antígeno?","back":"Es una sustancia extraña capaz de ser reconocida por el sistema inmunitario y desencadenar una respuesta específica.","topic":"Inmunología","difficulty":1,"fromOrientaciones":true},{"id":"bio-145","front":"¿Qué es un anticuerpo?","back":"Es una inmunoglobulina producida por linfocitos B o células plasmáticas que reconoce de forma específica un antígeno.","topic":"Inmunología","difficulty":1,"fromOrientaciones":true},{"id":"bio-146","front":"¿Qué diferencia general existe entre inmunidad innata e inmunidad específica?","back":"La inmunidad innata es inespecífica y actúa de forma inmediata, mientras que la específica reconoce antígenos concretos y desarrolla memoria.","topic":"Inmunología","difficulty":2,"fromOrientaciones":true},{"id":"bio-147","front":"¿Qué barreras externas dificultan la entrada de patógenos en el organismo?","back":"Las barreras mecánicas como piel y mucosas, las químicas como secreciones ácidas o enzimáticas, y la microbiota como barrera biológica.","topic":"Inmunología","difficulty":2,"fromOrientaciones":true},{"id":"bio-148","front":"¿Qué es la inflamación?","back":"Es una respuesta inespecífica del organismo frente a una agresión, asociada a vasodilatación, aumento de permeabilidad y salida de células defensivas.","topic":"Inmunología","difficulty":2,"fromOrientaciones":true},{"id":"bio-149","front":"¿Qué células son responsables de la producción de anticuerpos?","back":"Los linfocitos B, que al activarse pueden diferenciarse en células plasmáticas secretoras de anticuerpos.","topic":"Inmunología","difficulty":2,"fromOrientaciones":true},{"id":"bio-150","front":"¿Cuál es la causa inmunológica principal del rechazo de un trasplante?","back":"La incompatibilidad entre moléculas del complejo principal de histocompatibilidad del donante y del receptor, lo que activa la respuesta inmune.","topic":"Inmunología","difficulty":3,"fromOrientaciones":true}]'),a={subject:e,flashcards:i};export{a as default,i as flashcards,e as subject};
